mapper.select:
 
		 
		select 
			userid, auth
		from ( 
				select 
					 ROWNUM rn, userid, auth
				from (
						select userid, auth
						  from cotdl.tbl_member_auth 
						 order by auth
					 ) r
				where  userid != 'admin' and
		
	    
		
						
							and upper(userid) like '%'||upper(#{search1})||'%'
						
						
							and upper(auth) like '%'||upper(#{search2})||'%'
						
		
	    
	    
				 ROWNUM <= #{pagenum} * #{amount} 
				order by auth 
			  ) f
		where rn > (#{pagenum} -1) * #{amount} 
		order by auth
